69	\section{Universal property and the cotangent exact sequence}
70	
71	\begin{definition}\leanok
72	[Universal derivation]
73	  \label{def:universal_derivation}
74	  \lean{AlgebraicGeometry.Scheme.universalDerivation}
75	  \uses{def:relative_kaehler_sheaf}
76	  The morphism of sheaves of abelian groups $\mathrm{d} \colon \struct{X} \to \Omega_{X/S}$, defined on each affine open $V = \Spec B$ over $\Spec A$ by the Mathlib universal derivation $\mathrm{d}_{B/A} \colon B \to \Omega_{B/A}$, is the \emph{universal derivation}. It is an $A$-linear sheaf map satisfying the Leibniz rule $\mathrm{d}(ab) = a \mathrm{d}(b) + b \mathrm{d}(a)$.
77	\end{definition}
78	
79	The cotangent exact sequence is decomposed into three named ingredients before being assembled into a single theorem.
80	
81	\begin{definition}\leanok
82	[Base-change cotangent map $\alpha$]
83	  \label{def:cotangent_alpha}
84	  \lean{AlgebraicGeometry.Scheme.cotangentExactSeqAlpha}
85	  \uses{def:relative_kaehler_sheaf}
86	  For schemes $X \xrightarrow{f} Y \xrightarrow{g} S$ the \emph{base-change cotangent map} is the natural morphism of quasi-coherent $\struct{X}$-modules
87	  \[
88	    \alpha \colon f^*\Omega_{Y/S} \;\longrightarrow\; \Omega_{X/S}
89	  \]
90	  whose local description on an affine chart with rings $A = \struct{S}(W)$, $A' = \struct{Y}(f(V))$, $B = \struct{X}(V)$ is the standard map $\Omega_{A'/A} \otimes_{A'} B \to \Omega_{B/A}$ of K\"ahler differentials, $da \otimes b \mapsto b \cdot da$.
91	\end{definition}
92	
93	\begin{definition}\leanok
94	[Relative-quotient cotangent map $\beta$]
95	  \label{def:cotangent_beta}
96	  \lean{AlgebraicGeometry.Scheme.cotangentExactSeqBeta}
97	  \uses{def:relative_kaehler_sheaf}
98	  For schemes $X \xrightarrow{f} Y \xrightarrow{g} S$ the \emph{relative-quotient cotangent map} is the natural surjection of quasi-coherent $\struct{X}$-modules
99	  \[
